// ============================================================
// INJECT INTO ALL 5 JSON FILES
// ============================================================
for (const lang of LANGS) {
  const filePath = path.join(MESSAGES_DIR, lang + '.json');
  const content = fs.readFileSync(filePath, 'utf-8');
  const data = JSON.parse(content);

  for (const [ns, translations] of Object.entries(seoData)) {
    if (!data[ns]) {
      console.log('WARNING: namespace ' + ns + ' not found in ' + lang + '.json, skipping');
      continue;
    }
    if (data[ns].seo) {
      console.log('INFO: ' + ns + '.seo already exists in ' + lang + '.json, skipping');
      continue;
    }
    data[ns].seo = translations[lang];
    console.log('ADDED: ' + ns + '.seo to ' + lang + '.json (' + Object.keys(translations[lang]).length + ' keys)');
  }

  fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + '\n', 'utf-8');
}

console.log('\nDone adding SEO translation keys.');
